fun main() {
    // Immutable
    val readOnly = listOf("A", "B", "C")
    // readOnly.add("D")  // Error - not available

    // Mutable
    val mutable = mutableListOf("X", "Y", "Z")
    mutable.add("W")
    println("Mutable: $mutable")

    // Read-only view of mutable
    val view: List<String> = mutable
    mutable.add("V")
    println("View reflects change: $view")  // [X, Y, Z, W, V]

    // Defensive copy
    val safeCopy = mutable.toList()
    mutable.add("U")
    println("Copy unchanged: $safeCopy")
}
